sys_script_client.script:
function onLoad() {
const customerNumber = state.selectedCustomerNumber;
  if (!customerNumber) return;
  const ga = new GlideAjax('CustomerOfferHelper');
  ga.addParam('sysparm_name', 'getOfferDefaults');
  ga.addParam('sysparm_customer_number', customerNumber);
  ga.getXMLAnswer(function (response) {
    const data = JSON.parse(response);
    if (data.error) {
      console.error(data.error);
      return;
    }

    // Bind these to your modal form fields
    state.offerType = data.offer_type;
    state.delinquencyStatus = data.delinquency_status;
    state.customerNumber = data.customer_number;
    state.delinquencyCount = data.delinquency_count;
  });
}
